(window.webpackJsonp=window.webpackJsonp||[]).push([[351],{978:function(n,e){n.exports="\x3c!-- \ntitle: 01-Flutter入门\nsort: \n--\x3e \n\n## HelloWorld\n\n> [文档](https://api.flutter.dev/)\n\n```dart\nimport 'package:flutter/material.dart';\n\n// 入口函数\nvoid main() {\n  runApp(\n    new Center(\n      child: new Text(\n        'Hello, world!',\n        textDirection: TextDirection.ltr,\n      ),\n    ),\n  );\n}\n```\n\n### 调用类\n\n```dart\nimport 'package:flutter/material.dart';\n\n// 入口函数\nvoid main() => runApp(MyApp());\n\n// MyApp类\nclass MyApp extends StatelessWidget {\n  // 重写build方法\n  @override\n  Widget build(BuildContext context) {\n    // 返回一个Material风格的组件\n    return MaterialApp(\n      title: 'Welcome to Flutteraa',\n      home: Scaffold(\n        // 创建一个Bar\n        appBar: AppBar(\n          title: Text('Welcome to Flutter'),\n        ),\n        // 主体添加一个hello world\n        body: Center(\n          child: Text('Hello World'),\n        ),\n      ),\n    );\n  }\n```\n\n## 组件\n\n### 文本\n\n```dart\nimport 'package:flutter/material.dart';\n\nvoid main() => runApp(MyApp());\n\nclass MyApp extends StatelessWidget {\n  @override\n  Widget build(BuildContext context) {\n    return MaterialApp(\n      title: 'Text widget',\n      home: Scaffold(\n        body: Center(\n            child: Text(\n          '测试~',\n          // 文本位置\n          textAlign: TextAlign.left,\n          // 超出长度的隐藏方式\n          overflow: TextOverflow.ellipsis,\n          // 最长行数\n          maxLines: 1,\n          // 样式 \n          style: TextStyle(\n            fontSize: 25.0,\n            color: Color.fromARGB(255, 255, 255, 150),\n            decoration: TextDecoration.underline,\n            decorationStyle: TextDecorationStyle.solid,\n          ),\n        )),\n      ),\n    );\n  }\n}\n```\n\n### 容器"}}]);